138	export default async function handler(req: VercelRequest, res: VercelResponse) {
139	  if (req.method !== "POST") {
140	    return res.status(405).json({ error: "Method Not Allowed" });
141	  }
142	
143	  const { email, score } = req.body as { email?: string; score?: number };
144	
145	  if (!email || typeof score !== "number") {
146	    return res.status(400).json({ error: "email and score are required" });
147	  }
148	
149	  const errors: string[] = [];
150	
151	  // 1. Add contact to Resend Audience
152	  if (AUDIENCE_ID) {
153	    try {
154	      await resend.contacts.create({
155	        email,
156	        audienceId: AUDIENCE_ID,
157	        unsubscribed: false,
158	      });
159	    } catch (err) {
160	      errors.push(`audience: ${err}`);
161	    }
162	  }
163	
164	  // 2. Send Privacy Score email to the user
165	  try {
166	    await resend.emails.send({
167	      from: FROM_EMAIL,
168	      to: email,
169	      subject: `Tu Privacy Score: ${score}/100 — ${getCategoryLabel(score)}`,
170	      html: buildEmailHtml(score),
171	    });
172	  } catch (err) {
173	    errors.push(`email: ${err}`);
174	  }
175	
176	  if (errors.length > 0) {
177	    console.error("Resend errors:", errors);
178	  }
179	
180	  // Always return 200 — errors are non-blocking for the user experience
181	  return res.status(200).json({ success: true });
182	}
